import sys
from functools import reduce

class Solution:

def trailingZeroCount(self, n, arr):
	return reduce(lambda x, y: x + bin(y).count("0"), arr, 0)

if __name__ == '__main__':
	t = int(input())
	arr = list(map(int, input().split()))
	print(Solution().trailingZeroCount(t, arr))

