#include <iostream>
#include <bitset>
#include <vector>
using namespace std;

int trailingZeroCount(int n, int *arr) {
	return accumulate(arr, arr + n, 0, [] (int a, int b) { return (a + bitset<32>(b).count(0)); });
}

int main() {
	int n;
	cin >> n;
	int *arr = new int[n];
	for(int i = 0; i < n; i++)
		cin >> arr[i];
	cout << trailingZeroCount(n, arr) << endl;
	delete[] arr;
	return 0;
}
